const input = $json.body || $json;
const errors = [];

if (!input.type || !['trip', 'expense', 'vehicle'].includes(input.type)) {
  errors.push('type must be: trip, expense, or vehicle');
}
if (!input.host_id) errors.push('host_id is required');
if (!input.data) errors.push('data object is required');

if (input.type === 'trip') {
  if (!input.data.vehicle_id) errors.push('data.vehicle_id required');
  if (!input.data.trip_start) errors.push('data.trip_start required');
  if (!input.data.trip_end) errors.push('data.trip_end required');
  if (!input.data.daily_rate || input.data.daily_rate <= 0) errors.push('data.daily_rate must be positive');
}

if (input.type === 'expense') {
  if (!input.data.vehicle_id) errors.push('data.vehicle_id required');
  if (!input.data.amount || input.data.amount <= 0) errors.push('data.amount must be positive');
  if (!input.data.category) errors.push('data.category required');
}

if (errors.length > 0) {
  return [{ json: { valid: false, errors } }];
}

// Calculate derived fields for trips
if (input.type === 'trip') {
  const start = new Date(input.data.trip_start);
  const end = new Date(input.data.trip_end);
  const days = Math.ceil((end - start) / (1000 * 60 * 60 * 24));
  input.data.days = days;
  input.data.gross_revenue = (days * input.data.daily_rate).toFixed(2);
}

return [{ json: { valid: true, ...input } }];

const items = $input.all();
// Expect data from multiple sheet reads merged
const vehicles = items.filter(i => i.json['Vehicle ID'] && i.json['Make']);
const trips = items.filter(i => i.json['Trip Start'] && i.json['Daily Rate']);
const expenses = items.filter(i => i.json['Category'] && i.json['Amount']);
const now = new Date();
const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);

const dashboard = vehicles.filter(v => v.json.Active === 'TRUE').map(vehicle => {
  const vid = vehicle.json['Vehicle ID'];
  const monthTrips = trips.filter(t => t.json['Vehicle ID'] === vid && new Date(t.json['Trip Start']) >= monthStart);
  const monthExpenses = expenses.filter(e => e.json['Vehicle ID'] === vid && new Date(e.json['Date']) >= monthStart);

  const revenue = monthTrips.reduce((s, t) => s + (Number(t.json['Gross Revenue']) || 0), 0);
  const platformFees = monthTrips.reduce((s, t) => s + (Number(t.json['Platform Fees']) || 0), 0);
  const varCosts = monthExpenses.reduce((s, e) => s + (Number(e.json['Amount']) || 0), 0);
  const fixedCosts = (Number(vehicle.json['Monthly Insurance']) || 0) + (Number(vehicle.json['Monthly Parking']) || 0) + (Number(vehicle.json['Monthly Loan']) || 0);
  const totalCosts = varCosts + fixedCosts;
  const netProfit = revenue - platformFees - totalCosts;
  const daysBooked = monthTrips.reduce((s, t) => s + (Number(t.json['Days']) || 0), 0);

  return {
    json: {
      'Vehicle': vehicle.json.Make + ' ' + vehicle.json.Model + ' ' + vehicle.json.Year,
      'This Month Revenue': revenue.toFixed(2),
      'This Month Costs': totalCosts.toFixed(2),
      'Net Profit': netProfit.toFixed(2),
      'Profit Margin %': revenue > 0 ? ((netProfit / revenue) * 100).toFixed(1) : '0.0',
      'Days Booked': daysBooked,
      'Utilization %': ((daysBooked / 30) * 100).toFixed(1),
      'Last Updated': now.toISOString()
    }
  };
});

return dashboard.length > 0 ? dashboard : [{ json: { message: 'No active vehicles found' } }];

const items = $input.all();
const vehicles = items.filter(i => i.json['Vehicle ID'] && i.json['Make']);
const trips = items.filter(i => i.json['Trip Start'] && i.json['Daily Rate']);
const expenses = items.filter(i => i.json['Category'] && i.json['Amount']);
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

let report = 'FLEET Weekly Report - ' + now.toISOString().slice(0, 10) + '\n\n';

const activeVehicles = vehicles.filter(v => v.json.Active === 'TRUE');
let totalRevenue = 0, totalCosts = 0;

activeVehicles.forEach(v => {
  const vid = v.json['Vehicle ID'];
  const weekTrips = trips.filter(t => t.json['Vehicle ID'] === vid && new Date(t.json['Trip Start']) >= weekAgo);
  const weekExpenses = expenses.filter(e => e.json['Vehicle ID'] === vid && new Date(e.json['Date']) >= weekAgo);

  const rev = weekTrips.reduce((s, t) => s + (Number(t.json['Net Revenue']) || 0), 0);
  const costs = weekExpenses.reduce((s, e) => s + (Number(e.json['Amount']) || 0), 0);
  const days = weekTrips.reduce((s, t) => s + (Number(t.json['Days']) || 0), 0);

  totalRevenue += rev;
  totalCosts += costs;

  report += v.json.Make + ' ' + v.json.Model + ' ' + v.json.Year + ' (' + vid + '):\n';
  report += '  Revenue: $' + rev.toFixed(2) + ' | Costs: $' + costs.toFixed(2) + ' | Profit: $' + (rev - costs).toFixed(2) + '\n';
  report += '  Days booked: ' + days + '/7 (' + ((days/7)*100).toFixed(0) + '% utilization)\n\n';
});

report += 'FLEET TOTAL: Revenue $' + totalRevenue.toFixed(2) + ' | Costs $' + totalCosts.toFixed(2) + ' | Net $' + (totalRevenue - totalCosts).toFixed(2) + '\n';

return [{ json: { report, generated: now.toISOString() } }];

try {
  const { task, data } = JSON.parse(query);

  if (task === 'break_even') {
    const monthly_fixed = (Number(data.insurance) || 0) + (Number(data.parking) || 0) + (Number(data.loan_payment) || 0);
    const target_days = Number(data.target_days) || 20;
    const variable_per_day = (Number(data.gas_per_day) || 5) + (Number(data.cleaning_per_trip) || 15) / (Number(data.avg_trip_days) || 3);
    const depreciation_per_day = (Number(data.purchase_price) || 25000) * 0.15 / 365;
    const platform_fee = Number(data.platform_fee_pct) || 25;
    const protection = Number(data.protection_plan_pct) || 0;
    const host_pct = (100 - platform_fee - protection) / 100;
    const daily_cost = (monthly_fixed / target_days) + variable_per_day + depreciation_per_day;
    const min_rate = daily_cost / host_pct;
    return JSON.stringify({
      monthly_fixed_costs: monthly_fixed.toFixed(2),
      daily_fixed_portion: (monthly_fixed / target_days).toFixed(2),
      variable_per_day: variable_per_day.toFixed(2),
      depreciation_per_day: depreciation_per_day.toFixed(2),
      total_daily_cost: daily_cost.toFixed(2),
      host_receive_pct: (host_pct * 100).toFixed(1) + '%',
      minimum_daily_rate: Math.ceil(min_rate),
      recommended_rate: Math.ceil(min_rate * 1.2),
      explanation: 'Min rate covers all costs. Recommended adds 20% profit margin.'
    });
  }

  if (task === 'monthly_pnl') {
    const trips = data.trips || [];
    const expenses = data.expenses || [];
    const fixed = (Number(data.insurance) || 0) + (Number(data.parking) || 0) + (Number(data.loan_payment) || 0);
    const gross = trips.reduce((s, t) => s + (Number(t.gross_revenue) || Number(t.daily_rate) * Number(t.days) || 0), 0);
    const platformFees = trips.reduce((s, t) => s + (Number(t.platform_fees) || gross * (Number(data.platform_fee_pct) || 25) / 100 / trips.length), 0);
    const protection = trips.reduce((s, t) => s + (Number(t.protection_cost) || 0), 0);
    const variable = expenses.reduce((s, e) => s + (Number(e.amount) || 0), 0);
    const totalDays = trips.reduce((s, t) => s + (Number(t.days) || 0), 0);
    const net = gross - platformFees - protection - variable - fixed;
    return JSON.stringify({
      gross_revenue: gross.toFixed(2),
      platform_fees: platformFees.toFixed(2),
      protection_costs: protection.toFixed(2),
      variable_costs: variable.toFixed(2),
      fixed_costs: fixed.toFixed(2),
      net_profit: net.toFixed(2),
      profit_margin: gross > 0 ? ((net / gross) * 100).toFixed(1) + '%' : '0%',
      days_booked: totalDays,
      utilization: ((totalDays / 30) * 100).toFixed(1) + '%',
      avg_daily_net: totalDays > 0 ? (net / totalDays).toFixed(2) : '0'
    });
  }

  if (task === 'pricing_recommendation') {
    const breakEven = Number(data.break_even_rate) || 40;
    const marketAvg = Number(data.market_avg_rate) || 60;
    const utilization = Number(data.current_utilization) || 50;
    let recommended = marketAvg;
    if (utilization < 40) recommended = Math.max(breakEven, marketAvg * 0.85);
    else if (utilization < 60) recommended = marketAvg * 0.95;
    else if (utilization > 80) recommended = marketAvg * 1.15;
    else if (utilization > 90) recommended = marketAvg * 1.25;
    return JSON.stringify({
      break_even_rate: breakEven,
      market_average: marketAvg,
      current_utilization: utilization + '%',
      recommended_rate: Math.ceil(recommended),
      strategy: utilization < 40 ? 'LOWER rate to increase bookings' : utilization > 80 ? 'RAISE rate to maximize revenue' : 'HOLD rate near market average',
      daily_profit_at_recommended: (recommended * (1 - (Number(data.platform_fee_pct) || 25) / 100) - breakEven).toFixed(2)
    });
  }

  if (task === 'roi') {
    const purchase = Number(data.purchase_price) || 25000;
    const monthlyNet = Number(data.monthly_net_profit) || 500;
    const annualNet = monthlyNet * 12;
    const roi = (annualNet / purchase) * 100;
    const paybackMonths = monthlyNet > 0 ? Math.ceil(purchase / monthlyNet) : 999;
    return JSON.stringify({
      purchase_price: purchase,
      monthly_net_profit: monthlyNet.toFixed(2),
      annual_net_profit: annualNet.toFixed(2),
      annual_roi: roi.toFixed(1) + '%',
      payback_months: paybackMonths,
      payback_years: (paybackMonths / 12).toFixed(1),
      verdict: roi > 20 ? 'Excellent investment' : roi > 10 ? 'Good investment' : roi > 5 ? 'Marginal - consider alternatives' : 'Poor ROI - reconsider'
    });
  }

  if (task === 'depreciation') {
    const purchase = Number(data.purchase_price) || 25000;
    const miles = Number(data.annual_miles) || 15000;
    const irsPerMile = 0.33;
    const annualDep = miles * irsPerMile;
    const monthlyDep = annualDep / 12;
    const dailyDep = annualDep / 365;
    return JSON.stringify({
      purchase_price: purchase,
      annual_miles: miles,
      irs_rate_per_mile: irsPerMile,
      annual_depreciation: annualDep.toFixed(2),
      monthly_depreciation: monthlyDep.toFixed(2),
      daily_depreciation: dailyDep.toFixed(2),
      years_to_zero: (purchase / annualDep).toFixed(1)
    });
  }

  if (task === 'fuel_cost_estimate') {
    const mpg = Number(data.mpg) || 28;
    const milesPerTrip = Number(data.miles_per_trip) || 100;
    const gasPrice = Number(data.gas_price_per_gallon) || 3.50;
    const gallonsUsed = milesPerTrip / mpg;
    const fuelCost = gallonsUsed * gasPrice;
    return JSON.stringify({
      mpg: mpg,
      miles_per_trip: milesPerTrip,
      gas_price: gasPrice.toFixed(2),
      gallons_used: gallonsUsed.toFixed(2),
      fuel_cost_per_trip: fuelCost.toFixed(2),
      cost_per_mile: (fuelCost / milesPerTrip).toFixed(3)
    });
  }

  return JSON.stringify({ error: 'Unknown task. Available: break_even, monthly_pnl, pricing_recommendation, roi, depreciation, fuel_cost_estimate' });
} catch (e) {
  return 'Error: ' + e.message;
}

try {
  const { task, data } = JSON.parse(query);

  if (task === 'market_analysis') {
    const rates = (data.competitor_rates || []).map(Number).filter(r => r > 0);
    if (rates.length === 0) return JSON.stringify({ error: 'No competitor rates provided' });
    const sorted = [...rates].sort((a, b) => a - b);
    const avg = rates.reduce((a, b) => a + b, 0) / rates.length;
    const median = sorted.length % 2 === 0
      ? (sorted[sorted.length/2 - 1] + sorted[sorted.length/2]) / 2
      : sorted[Math.floor(sorted.length/2)];
    const myRate = Number(data.my_rate) || 0;
    const percentile = myRate > 0 ? (sorted.filter(r => r <= myRate).length / sorted.length * 100) : 0;
    return JSON.stringify({
      sample_size: rates.length,
      average: avg.toFixed(2),
      median: median.toFixed(2),
      min: sorted[0].toFixed(2),
      max: sorted[sorted.length - 1].toFixed(2),
      std_dev: Math.sqrt(rates.reduce((s, r) => s + Math.pow(r - avg, 2), 0) / rates.length).toFixed(2),
      my_rate: myRate.toFixed(2),
      my_percentile: percentile.toFixed(0) + 'th',
      position: myRate < avg * 0.85 ? 'significantly_below_market'
        : myRate < avg * 0.95 ? 'below_market'
        : myRate < avg * 1.05 ? 'at_market'
        : myRate < avg * 1.15 ? 'above_market'
        : 'significantly_above_market'
    });
  }

  if (task === 'seasonal_adjustment') {
    const base = Number(data.base_rate) || 50;
    const month = Number(data.month) || new Date().getMonth() + 1;
    const isHoliday = data.is_holiday_weekend || false;
    const seasonal = {1:0.85, 2:0.85, 3:0.95, 4:1.0, 5:1.1, 6:1.2, 7:1.25, 8:1.2, 9:1.05, 10:1.0, 11:0.95, 12:1.15};
    const multiplier = seasonal[month] || 1.0;
    const holidayBoost = isHoliday ? 1.3 : 1.0;
    const adjusted = base * multiplier * holidayBoost;
    return JSON.stringify({
      base_rate: base.toFixed(2),
      month: month,
      seasonal_multiplier: multiplier,
      holiday_boost: holidayBoost,
      adjusted_rate: Math.ceil(adjusted),
      explanation: (multiplier > 1 ? 'Peak' : multiplier < 1 ? 'Off' : 'Normal') + ' season (' + multiplier + 'x)' + (isHoliday ? ' + holiday weekend (1.3x)' : '')
    });
  }

  if (task === 'fleet_comparison') {
    const vehicles = data.vehicles || [];
    if (vehicles.length === 0) return JSON.stringify({ error: 'No vehicles provided' });
    const ranked = vehicles.map(v => {
      const profit = (Number(v.monthly_revenue) || 0) - (Number(v.monthly_costs) || 0);
      const margin = v.monthly_revenue > 0 ? (profit / v.monthly_revenue * 100) : 0;
      const utilization = (Number(v.days_booked) || 0) / 30 * 100;
      const annualROI = v.purchase_price > 0 ? (profit * 12 / v.purchase_price * 100) : 0;
      return { ...v, profit: profit.toFixed(2), margin: margin.toFixed(1), utilization: utilization.toFixed(1), annual_roi: annualROI.toFixed(1) };
    }).sort((a, b) => Number(b.profit) - Number(a.profit));
    return JSON.stringify({
      fleet_size: vehicles.length,
      total_revenue: vehicles.reduce((s, v) => s + (Number(v.monthly_revenue) || 0), 0).toFixed(2),
      total_costs: vehicles.reduce((s, v) => s + (Number(v.monthly_costs) || 0), 0).toFixed(2),
      total_profit: ranked.reduce((s, v) => s + Number(v.profit), 0).toFixed(2),
      best_performer: ranked[0]?.id || 'none',
      worst_performer: ranked[ranked.length - 1]?.id || 'none',
      vehicles_ranked: ranked
    });
  }

  return JSON.stringify({ error: 'Unknown task. Available: market_analysis, seasonal_adjustment, fleet_comparison' });
} catch (e) {
  return 'Error: ' + e.message;
}

try {
  const { task, data } = JSON.parse(query);

  if (task === 'validate_vehicle') {
    const errors = [];
    if (!data.make || data.make.length < 2) errors.push('make is required');
    if (!data.model || data.model.length < 1) errors.push('model is required');
    if (!data.year || data.year < 1990 || data.year > 2027) errors.push('year must be 1990-2027');
    if (!data.city) errors.push('city is required');
    if (!data.state || data.state.length !== 2) errors.push('state must be 2-letter abbreviation');
    if (data.purchase_price && data.purchase_price < 0) errors.push('purchase_price cannot be negative');
    if (data.platform_fee_pct && (data.platform_fee_pct < 0 || data.platform_fee_pct > 100)) errors.push('platform_fee_pct must be 0-100');
    if (data.protection_plan_pct && (data.protection_plan_pct < 0 || data.protection_plan_pct > 100)) errors.push('protection_plan_pct must be 0-100');
    return JSON.stringify({ valid: errors.length === 0, errors, data });
  }

  if (task === 'validate_expense') {
    const errors = [];
    const validCategories = ['gas', 'repair', 'maintenance', 'cleaning', 'insurance', 'parking', 'registration', 'toll', 'ticket', 'other'];
    if (!data.vehicle_id) errors.push('vehicle_id required');
    if (!data.amount || data.amount <= 0) errors.push('amount must be positive');
    if (!data.category || !validCategories.includes(data.category.toLowerCase())) {
      errors.push('category must be one of: ' + validCategories.join(', '));
    }
    if (data.date) {
      const d = new Date(data.date);
      if (isNaN(d.getTime())) errors.push('date format invalid (use YYYY-MM-DD)');
    }
    return JSON.stringify({ valid: errors.length === 0, errors, data });
  }

  if (task === 'validate_trip') {
    const errors = [];
    if (!data.vehicle_id) errors.push('vehicle_id required');
    if (!data.trip_start) errors.push('trip_start required (YYYY-MM-DD)');
    if (!data.trip_end) errors.push('trip_end required (YYYY-MM-DD)');
    if (!data.daily_rate || data.daily_rate <= 0) errors.push('daily_rate must be positive');
    if (data.trip_start && data.trip_end) {
      const start = new Date(data.trip_start);
      const end = new Date(data.trip_end);
      if (end <= start) errors.push('trip_end must be after trip_start');
      const days = Math.ceil((end - start) / (1000 * 60 * 60 * 24));
      if (days > 90) errors.push('trip cannot exceed 90 days');
    }
    if (data.miles_driven && data.miles_driven < 0) errors.push('miles_driven cannot be negative');
    return JSON.stringify({ valid: errors.length === 0, errors, data });
  }

  if (task === 'dedup_check') {
    const existing = data.existing_trips || [];
    const nt = data.new_trip || {};
    const isDuplicate = existing.some(t =>
      t.vehicle_id === nt.vehicle_id &&
      t.trip_start === nt.trip_start &&
      t.trip_end === nt.trip_end
    );
    return JSON.stringify({ is_duplicate: isDuplicate, new_trip: nt });
  }

  return JSON.stringify({ error: 'Unknown task. Available: validate_vehicle, validate_expense, validate_trip, dedup_check' });
} catch (e) {
  return 'Error: ' + e.message;
}

const error = $json;
const timestamp = new Date().toISOString();
const errorInfo = {
  timestamp,
  workflow: 'FLEET Advisor v3',
  error_message: error.message || 'Unknown error',
  error_type: error.name || 'Error',
  node: error.node || 'unknown',
  execution_id: error.execution?.id || 'unknown'
};
return [{ json: errorInfo }];
